import{_ as t,c as d,o as e,a5 as a}from"./chunks/framework.D1VOoOiA.js";const m=JSON.parse('{"title":"Text  文本","description":"","frontmatter":{},"headers":[],"relativePath":"components/sn-text.md","filePath":"components/sn-text.md"}'),r={name:"components/sn-text.md"},o=a('<h1 id="text-文本" tabindex="-1">Text 文本 <a class="header-anchor" href="#text-文本" aria-label="Permalink to &quot;Text  文本&quot;">​</a></h1><h2 id="基本使用" tabindex="-1">基本使用 <a class="header-anchor" href="#基本使用" aria-label="Permalink to &quot;基本使用&quot;">​</a></h2><ul><li>只支持通过 <code>text</code> 属性传值（这个要是用插槽，反而会多套一层 <code>text</code></li></ul><div class="language-vue vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vue</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">sn-text</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> text</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;这是一段文本&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">sn-text</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><p><strong>更多演示请下载 demo 查看</strong></p><h2 id="文本模式" tabindex="-1">文本模式 <a class="header-anchor" href="#文本模式" aria-label="Permalink to &quot;文本模式&quot;">​</a></h2><p>目前支持通过 <code>mode</code> 属性设置文本的模式，轻松实现常见功能，为您减少代码量。</p><ul><li><p>text</p><p>默认模式，与内置 <code>text</code> 组件无异。</p></li><li><p>date</p><p>日期模式，支持通过传入时间戳（需转换为String类型），实现自动格式化日期为 <code>yyyy-mm-dd</code> 的形式（以后会支持自定义格式）。</p></li><li><p>date-cn</p><p>日期模式（中文），与 <code>date</code> 用法相同，但是能转成中文 <code>yyyy年mm月dd日</code>。</p></li><li><p>price</p><p>价格模式，很简单的功能，将传入的文本前加一个 ￥（挺没用的哈，以后可能会加以改进，支持更多功能，比如汇率、国际化之类的）</p></li><li><p>price-upper</p><p>价格模式（大写），自动识别传入数字，并将其转换为中文大写金额，精确到分。</p><p>例：<code>168201.03 =&gt; 壹拾陆万捌仟贰佰零壹元零叁分</code></p></li><li><p>name</p><p>姓名模式，需搭配 <code>encrypt</code> 属性使用，否则与 <code>text</code> 模式效果相同。</p></li><li><p>phone</p><p>电话模式，点击后向用户发送请求，用户同意后直接拨打电话。</p></li><li><p>phone-direct</p><p>电话模式（直接拨打），点击后无需征求用户同意，直接拨打电话（但如果没有权限，还是会先请求拨号权限）。</p></li></ul><h2 id="api" tabindex="-1">API <a class="header-anchor" href="#api" aria-label="Permalink to &quot;API&quot;">​</a></h2><h3 id="text-props" tabindex="-1">Text Props <a class="header-anchor" href="#text-props" aria-label="Permalink to &quot;Text Props&quot;">​</a></h3><table tabindex="0"><thead><tr><th>参数</th><th>说明</th><th>类型</th><th>默认值</th><th>可选值</th></tr></thead><tbody><tr><td>mode</td><td>文本模式</td><td>String</td><td>text</td><td>text | date | date-cn | price | price-upper | name | phone | phone-direct</td></tr><tr><td>text</td><td>文本内容</td><td>String</td><td>text</td><td>-</td></tr><tr><td>color</td><td>文本颜色</td><td>String</td><td>text</td><td>-</td></tr><tr><td>type</td><td>文本主题样式类型</td><td>String</td><td>info</td><td>info | primary | success | error | warning</td></tr><tr><td>font</td><td>文本字体名</td><td>String</td><td></td><td>-</td></tr><tr><td>align</td><td>文本对齐方式</td><td>String</td><td>center</td><td>center | left | right</td></tr><tr><td>size</td><td>文本字体大小</td><td>String</td><td>16px</td><td>-</td></tr><tr><td>bold</td><td>是否加粗</td><td>Boolean</td><td>false</td><td>true | false</td></tr><tr><td>encrypt</td><td>是否脱敏（仅当 <code>mode=&quot;name&quot;</code>和<code>mode=&quot;phone&quot;</code>、<code>mode=&quot;phone-direct&quot;</code> 生效）</td><td>Boolean</td><td>false</td><td>true | false</td></tr><tr><td>lines</td><td>文本最大行数</td><td>Number</td><td>0</td><td>-</td></tr><tr><td>lineHeight</td><td>文本行高</td><td>String</td><td>1.2</td><td>-</td></tr><tr><td>space</td><td>（同内置<code>text</code>）显示连续空格 <a href="https://doc.dcloud.net.cn/uni-app-x/component/text.html#text-space-values" target="_blank" rel="noreferrer">space</a></td><td>String</td><td>-</td><td>-</td></tr><tr><td>decode</td><td>（同内置<code>text</code>）是否解码</td><td>Boolean</td><td>false</td><td>true | false</td></tr><tr><td>selectable</td><td>（同内置<code>text</code>）文本是否可选</td><td>Boolean</td><td>false</td><td>true | false</td></tr><tr><td>customStyle</td><td>自定义文本样式</td><td>UTSJSONObject</td><td>{}</td><td>-</td></tr><tr><td>template</td><td>模板名称</td><td>String</td><td></td><td>-</td></tr></tbody></table>',11),i=[o];function s(n,p,l,c,h,u){return e(),d("div",null,i)}const g=t(r,[["render",s]]);export{m as __pageData,g as default};
